import random


class Solution:
    def __init__(self, head):
        self.head = head
    def getRandom(self):
        result = None
        node = self.head
        count = 0
        while node is not None:
            count += 1
            if random.randint(1, count) == count:
                result = node.val
            node = node.next
        return result

