var Solution = function(head) {
    this.head = head;
};
Solution.prototype.getRandom = function() {
    let result = null;
    let node = this.head;
    let count = 0;
    while (node !== null) {
        count += 1;
        if (Math.floor(Math.random() * count) === 0) {
            result = node.val;
        }
        node = node.next;
    }
    return result;
};
